SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE phone = #{phone}
)

SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE email = #{email}
)

SELECT id, handle, nickname, avatar, bio, tags_json, created_at
FROM users
WHERE id = #{id}

SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE handle = #{handle}
)

mapper.update:
UPDATE users
nickname = #{nickname}, bio = #{bio}, gender = #{gender}, birthday = #{birthday}, handle = #{handle}, school = #{school}, avatar = #{avatar}, tags_json = #{tagsJson}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE handle = #{handle}
      AND id != #{excludeId}
)

SELECT * FROM users
( nickname LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') OR handle LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY id DESC LIMIT #{limit} OFFSET #{offset}
